var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 다들 화면에 집중하세요.","JPN":"次は画面をご覧ください。","ENG":"Okay everyone, now focus on the screen.","TWN":"來，大家集中看畫面。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"총기 안전장치 관리를 소홀히 했다가 부상 입은 사례입니다. 사건 발생 개요부터 살펴 보자면......","JPN":"銃器の安全装置の管理を怠り、負傷に繋がった事例です。事件の発生概要については……","ENG":"This case of injury is from a negligent discharge of a firearm. It happened...","TWN":"這是因疏忽槍枝安全裝置管理而受傷的案例。從事件發生的概要來看的話…"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"할아버지, 이거 자장가 맞지?","JPN":"おじいちゃん、これ子守歌だよね？","ENG":"Grandpa, doesn't this sound like a lullaby to you?","TWN":"爺爺，這是搖籃曲吧？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"으음......! 그래! 무시무시한 음파 병기의 일종이 틀림없는 것 같군!","JPN":"うむ……！　どうやら恐ろしい音波兵器のようだな！","ENG":"Mm... It does. It's got to be some sort of sonic wave-based weapon. So terrible!","TWN":"嗯......！對！ 這一定是可怕的音波兵器的一種！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카, 나 너무 졸려...... 교대하자......","JPN":"オルカ、眠すぎる……交代……","ENG":"Orca, I'm so sleepy... Switch with me...","TWN":"奧爾卡，我好睏啊...... 我們輪班吧......"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"지루해서 속이 메스꺼운 적은 오늘이 처음이야......","JPN":"初めてだぜ……退屈すぎて胃もたれするような経験は……","ENG":"I've never experienced anything so nauseatingly boring...","TWN":"今天是第一次感覺到無聊到有點噁心......"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"기어코 여길 끌고 오다니...... 이수연 녀석, 아직도 원한이 덜 풀렸나 보군.","JPN":"とうとう私をここに連れてくるとは……カナミのやつ、まだ恨みが晴れていないようだな。","ENG":"She had to drag me here. Lee Sooyeon's definitely still angry with me.","TWN":"偏偏要把我拉到這裡來……李秀妍這傢伙，看來到現在還沒有完全解恨啊。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배...... 선심 쓰듯이 가라고 하더니 자기만 쏙 빠져 나가고...... 가만 안 둘 줄 알아......","JPN":"先輩……私には行きなさいって言っておいて、\\n自分は逃げ出すなんて……許さない……","ENG":"Shiyoon... He acted as if he was doing me a favor coming here with me, and now he's gone. If I find him, he's a dead man...","TWN":"前輩...... 像發善心一樣讓我走，結果他自己卻溜走了……我不會放過他……"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어쩌죠, 부사장님. 이대로라면 절반도 듣기 전에 다들 쓰러지시겠어요.","JPN":"副社長、どうしましょう……まだ半分も終わってないのにみんな倒れそうな勢いです。","ENG":"Vice President, what do we do? At this rate, everyone's going to fall asleep before we even finish the first half.","TWN":"怎麼辦，副總。 照這樣下去，在聽到一半之前，大家都會暈倒的。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네. 제대로 안 들으면 재이수라고 했는데도 이 꼴이군요.","JPN":"まったく、ちゃんと聞かないと再履修だって伝えたのに、この調子だなんて。","ENG":"I know. I even told them they'd have to take it again if they didn't pay attention.","TWN":"對，如果不乖乖聽的話，會再進修，但還真是這樣。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그나저나 사장님도 참 대단하시네요. 아까부터 불평 한마디 안 하고 들으시잖아요.","JPN":"だけど社長はすごいですね！\\n文句の一言も言わず、しっかり聞いています。","ENG":"By the way, the Boss is doing incredibly well. He hasn't complained at all since we began.","TWN":"話說回來，老闆也真了不起。因為從剛才開始一句怨言都沒有。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"글쎄요. 제 눈에는 그냥 절전 모드인 걸로 보입니다만.","JPN":"そうですね……私には省エネモードに入ってるように見えますが。","ENG":"I don't know. To me, he looks like he's in sleep mode.","TWN":"這個嘛，在我看來，這只是一種省電模式罷了。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>편의점 아포칼립스 코핀 컴퍼니 지점</color>에서 <color=#ffd34c>어린이 요리 도구 세트</color> 2개 결재가 완료되었습니다.","JPN":"<color=#ffd34c>コンビニエンスストア[アポカリプス]コフィンカンパニー支店</color>で<color=#ffd34c>子どもクッキングセット</color>2個の支払いが完了しました。","ENG":"Two <color=#ffd34c>Children's Cooking Utensil Sets</color> have been purchased at the <color=#ffd34c>Apocalypse convenience store Coffin Company branch</color>.","TWN":"在<color=#ffd34c>便利商店阿波卡利斯科芬公司分店</color>支付了兩個 <color=#ffd34c>兒童料理道具組合</color>。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"대금은 회사로 청구됩니다. 하. 하. 하.","JPN":"代金は会社へ請求されます。はっ・はっ・は。","ENG":"They've been charged on the company credit card. Hah. Hah. Hah.","TWN":"費用會向公司請款。哈. 哈. 哈."},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"거기! 집중 안 하시면 교육 연장 합니다!","JPN":"そこ！　集中しないと研修を延長しますよ！","ENG":"Excuse me! Stay focused, or the class will be extended!","TWN":"那邊！如果不集中的話課程會延長喔！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 네! 죄송합니다!","JPN":"あっ、はい！　すみません……！","ENG":"Oops, sorry!","TWN":"啊，好！對不起！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"......"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};